1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface Customer {
9	  yearsWithMHPCO: number;
10	}
11	
12	interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: { cause: string; damages: Damage[] };
26	}
27	
28	type Step = QuoteStep | ClaimStep;
29	
30	interface Scenario {
31	  customer: Customer;
32	  steps: Step[];
33	}
34	
35	interface QuoteResult {
36	  premium: number;
37	}
38	
39	interface ClaimResult {
40	  payout: number;
41	  remainingCap: number;
42	}
43	
44	type StepResult = QuoteResult | ClaimResult;
45	
46	interface Policy {
47	  items: Item[];
48	  remainingCap: number;
49	}
50	
51	const BASE_PREMIUM: Record<string, number> = {
52	  sword: 100,
53	  amulet: 60,
54	  staff: 80,
55	  potion: 40,
56	  rune: 25,
57	};
58	
59	const INSURANCE_VALUE: Record<string, number> = {
60	  sword: 1000,
61	  amulet: 600,
62	  staff: 800,
63	  potion: 400,
64	  rune: 250,
65	  moonstone: 250,
66	};
67	
68	const DEDUCTIBLE = 100;
69	const CAP_MULTIPLIER = 2;
70	const HIGH_ENCH_PAYOUT_THRESHOLD = 8;
71	const HIGH_ENCH_PAYOUT_RATE = 0.5;
72	
73	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
74	const COMPONENT_BASE = 25;
75	const BLOCK_SIZE = 3;
76	const BLOCK_BASE = 60;
77	
78	const FIRST_INSURANCE_RATE = 0.1;
79	const CURSE_RATE = 0.5;
80	const HIGH_ENCHANTMENT_RATE = 0.3;
81	const HIGH_ENCHANTMENT_THRESHOLD = 5;
82	const LOYALTY_RATE = 0.2;
83	const LOYALTY_THRESHOLD = 2;
84	const FOLLOWUP_RATE = 0.15;
85	const PROCESSING_FEE = 5;
86	const ROUNDING_PRECISION = 6;
87	
88	const componentGroupBase = (count: number): number =>
89	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
90	
91	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
92	
93	const withSurcharge = (base: number, rate: number): number => base + base * rate;
94	
95	const isHighlyEnchanted = (item: Item): boolean =>
96	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
97	
98	const itemSurchargeRate = (item: Item): number =>
99	  FIRST_INSURANCE_RATE +
100	  (item.cursed ? CURSE_RATE : 0) +
101	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
102	
103	const mainItemPremium = (item: Item): number =>
104	  withSurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
105	
106	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
107	
108	const mainItemBaseSum = (items: Item[]): number =>
109	  mainItems(items).reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
110	
111	const mainItemTotal = (items: Item[]): number =>
112	  mainItems(items).reduce((sum, item) => sum + mainItemPremium(item), 0);
113	
114	const componentBaseSum = (items: Item[]): number => {
115	  const counts: Record<string, number> = {};
116	  for (const item of items.filter(isComponent)) {
117	    counts[item.type] = (counts[item.type] ?? 0) + 1;
118	  }
119	  return Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
120	};
121	
122	const componentTotal = (items: Item[]): number =>
123	  withSurcharge(componentBaseSum(items), FIRST_INSURANCE_RATE);
124	
125	const policyBase = (items: Item[]): number => mainItemBaseSum(items) + componentBaseSum(items);
126	
127	const policyDiscount = (items: Item[], rate: number, applies: boolean): number =>
128	  applies ? rate * policyBase(items) : 0;
129	
130	const loyaltyDiscount = (items: Item[], customer: Customer): number =>
131	  policyDiscount(items, LOYALTY_RATE, customer.yearsWithMHPCO >= LOYALTY_THRESHOLD);
132	
133	const followUpDiscount = (items: Item[], isFollowUp: boolean): number =>
134	  policyDiscount(items, FOLLOWUP_RATE, isFollowUp);
135	
136	const roundUpToWhole = (amount: number): number =>
137	  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));
138	
139	const itemPremiumSum = (items: Item[]): number =>
140	  mainItemTotal(items) + componentTotal(items);
141	
142	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number =>
143	  roundUpToWhole(
144	    itemPremiumSum(items) -
145	      loyaltyDiscount(items, customer) -
146	      followUpDiscount(items, isFollowUp) +
147	      PROCESSING_FEE,
148	  );
149	
150	const isQuote = (step: Step): boolean => step.op === "quote";
151	
152	const priorQuoteCount = (steps: Step[], index: number): number =>
153	  steps.slice(0, index).filter(isQuote).length;
154	
155	const insuranceSum = (items: Item[]): number =>
156	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
157	
158	const damageReimbursement = (item: Item | undefined, amount: number): number =>
159	  item && (item.enchantment ?? 0) >= HIGH_ENCH_PAYOUT_THRESHOLD
160	    ? HIGH_ENCH_PAYOUT_RATE * amount
161	    : amount;
162	
163	const damagePayout = (item: Item | undefined, damage: Damage): number =>
164	  damageReimbursement(item, damage.amount) - DEDUCTIBLE;
165	
166	const findInsuredItem = (items: Item[], itemType: string): Item | undefined =>
167	  items.find((item) => item.type === itemType);
168	
169	const incidentPayout = (damages: Damage[], items: Item[]): number =>
170	  damages.reduce(
171	    (sum, damage) => sum + damagePayout(findInsuredItem(items, damage.itemType), damage),
172	    0,
173	  );
174	
175	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
176	  const policy = policies[step.policy];
177	  const payout = incidentPayout(step.incident.damages, policy.items);
178	  policy.remainingCap -= payout;
179	  return { payout, remainingCap: policy.remainingCap };
180	};
181	
182	const processQuote = (
183	  step: QuoteStep,
184	  index: number,
185	  scenario: Scenario,
186	  policies: Policy[],
187	): QuoteResult => {
188	  const isFollowUp = priorQuoteCount(scenario.steps, index) > 0;
189	  policies[index] = {
190	    items: step.items,
191	    remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
192	  };
193	  return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
194	};
195	
196	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
197	  const policies: Policy[] = [];
198	  const results = scenario.steps.map((step, index): StepResult =>
199	    step.op === "claim"
200	      ? processClaim(step, policies)
201	      : processQuote(step, index, scenario, policies),
202	  );
203	  return { results };
204	};
